function buildCandidateMarkdown(dateLabel, digestRelativePath, candidates) {
  const currentKeywords = Array.isArray(data.keywords) ? data.keywords : [];
  const suggested = [...new Set([
    ...currentKeywords,
    ...candidates.filter((candidate) => candidate.category !== 'source-derived' || candidate.count >= 2).slice(0, 12).map((candidate) => candidate.term)
  ])];
  const rows = candidates.length
    ? candidates.map((candidate) => {
        const sources = candidate.sources.slice(0, 2).join('<br>') || '-';
        return `| ${candidate.term} | ${candidate.category} | ${candidate.count} | ${candidate.reasons.join('<br>')} | ${sources} |`;
      }).join('\n')
    : '| No candidates found | - | 0 | No source terms matched the extraction rules | - |';

  return [
    '---',
    'title: "Keyword Candidates"',
    `date: "${dateLabel}"`,
    `sourceDigest: "${digestRelativePath}"`,
    '---',
    '',
    `# Keyword Candidates - ${dateLabel}`,
    '',
    `Source digest: \`${digestRelativePath}\``,
    '',
    '## Current Keywords',
    '',
    currentKeywords.map((keyword) => `- ${keyword}`).join('\n') || '- (none)',
    '',
    '## Extracted Candidates',
    '',
    '| Candidate | Category | Count | Reason | Example sources |',
    '| --- | --- | ---: | --- | --- |',
    rows,
    '',
    '## Suggested Keyword List',
    '',
    '```js',
    `keywords: ${JSON.stringify(suggested, null, 2)}`,
    '```',
    '',
    '## Notes',
    '',
    '- Candidates are extracted heuristically from the saved digest and captured article text.',
    '- Review the list before adding terms to the production workflow.',
    '- Agency and company terms are prioritized for VTuber monitoring.',
    ''
  ].join('\n');
}

function markdownBinary(markdown, fileName) {
  return {
    data: Buffer.from(markdown, 'utf8').toString('base64'),
    mimeType: 'text/markdown',
    fileExtension: 'md',
    fileName
  };
}

